// Time:  O(n * s), s is the sum of nums.
// Space: O(s)

class Solution {
public:
    bool canPartition(vector<int>& nums) {
       const auto sum = accumulate(nums.cbegin(), nums.cend(), 0);
       if (sum % 2) {
           return false;
       }

       vector<bool> dp(sum / 2 + 1);
       dp[0]  = true;
       for (const auto& num : nums) {
           for (int i = dp.size() - 1; i >= 0; --i) {
               if (num <= i) {
                   dp[i] = dp[i] || dp[i - num];
               }
           }
       }
       return dp.back();
    }
};

# Time:  O(n * s), s is the sum of nums
# Space: O(s)

class Solution(object):
    def canPartition(self, nums):
        """
        :type nums: List[int]
        :rtype: bool
        """
        s = sum(nums)
        if s % 2:
            return False

        dp = [False] * (s/2 + 1)
        dp[0] = True
        for num in nums:
            for i in reversed(xrange(1, len(dp))):
                if num <= i:
                    dp[i] = dp[i] or dp[i - num]
        return dp[-1]
